/* ── Farbschema (Hell / Dunkel / System) ── */
const SCHEME_KEY = 'max4work_color_scheme';
const DARK_VARS = {
  standard: {'--bg':'#111312','--surface':'#1C1F1B','--border':'#2C2F2A','--text':'#E4E6E0','--muted':'#8A8D86','--soft':'#232622','--accent-pale':'#263010'},
  ios:      {'--bg':'#000000','--surface':'#1C1C1E','--border':'#38383A','--text':'#FFFFFF','--muted':'#8E8E93','--soft':'#2C2C2E','--accent-pale':'#0B2E5C'},
  android:  {'--bg':'#1C1B1F','--surface':'#28252C','--border':'#49454F','--text':'#E6E1E5','--muted':'#938F99','--soft':'#2D2B32','--accent-pale':'#21005D'}
};
let _schemeMQ = null;
function _sysMQCb() { applyColorScheme(localStorage.getItem(SCHEME_KEY)||'light'); }
function applyColorScheme(mode) {
  try { localStorage.setItem(SCHEME_KEY, mode); } catch(e) {}
  const dn = localStorage.getItem(APP_DESIGN_KEY) || 'standard';
  const d  = APP_DESIGNS[dn] || APP_DESIGNS.standard;
  const root = document.documentElement;
  Object.entries(d.vars).forEach(([k,v]) => root.style.setProperty(k,v));
  if (mode === 'split') {
    root.dataset.scheme = 'split';
  } else {
    const dk = mode==='dark' || (mode==='system' && window.matchMedia('(prefers-color-scheme: dark)').matches);
    if (dk) { const dv = DARK_VARS[dn]||DARK_VARS.standard; Object.entries(dv).forEach(([k,v]) => root.style.setProperty(k,v)); }
    root.dataset.scheme = dk ? 'dark' : 'light';
  }
  if (_schemeMQ) { _schemeMQ.removeEventListener('change', _sysMQCb); _schemeMQ = null; }
  if (mode==='system') { _schemeMQ = window.matchMedia('(prefers-color-scheme: dark)'); _schemeMQ.addEventListener('change', _sysMQCb); }
}
window.applyColorScheme = applyColorScheme;

function applyAppDesign(name) {
  const design = APP_DESIGNS[name] || APP_DESIGNS.standard;
  const root = document.documentElement;
  Object.entries(design.vars).forEach(([k, v]) => root.style.setProperty(k, v));
  root.setAttribute('data-design', name);
  const styleId = 'max4work-design-extra';
  let tag = document.getElementById(styleId);
  if (!tag) { tag = document.createElement('style'); tag.id = styleId; document.head.appendChild(tag); }
  tag.textContent = design.extraCSS || '';
  let fontTag = document.getElementById('max4work-design-font');
  if (!fontTag) { fontTag = document.createElement('style'); fontTag.id = 'max4work-design-font'; document.head.appendChild(fontTag); }
  fontTag.textContent = design.font ? `body,button,input,textarea,select{font-family:${design.font}!important;}` : '';
  if (name === 'android' && !document.getElementById('max4work-roboto-link')) {
    const lnk = document.createElement('link');
    lnk.id = 'max4work-roboto-link'; lnk.rel = 'stylesheet';
    lnk.href = 'https://fonts.googleapis.com/css2?family=Roboto:wght@300;400;500;700&display=swap';
    document.head.appendChild(lnk);
  }
  try { localStorage.setItem(APP_DESIGN_KEY, name); } catch(e) {}
  // Aktuelles Farbschema nach Design-Wechsel erneut anwenden
  const _sm = localStorage.getItem(SCHEME_KEY)||'light';
  if (_sm === 'split') {
    document.documentElement.dataset.scheme = 'split';
  } else {
    const _dk = _sm==='dark'||(_sm==='system'&&window.matchMedia('(prefers-color-scheme: dark)').matches);
    if (_dk) { const _dv=DARK_VARS[name]||DARK_VARS.standard; Object.entries(_dv).forEach(([k,v])=>root.style.setProperty(k,v)); }
    document.documentElement.dataset.scheme = _dk ? 'dark' : 'light';
  }
}

(function() {
  const saved = localStorage.getItem(APP_DESIGN_KEY);
  const dn = saved && APP_DESIGNS[saved] ? saved : 'standard';
  const d  = APP_DESIGNS[dn];
  const root = document.documentElement;
  Object.entries(d.vars).forEach(([k, v]) => root.style.setProperty(k, v));
  root.setAttribute('data-design', dn);
  // Farbschema sofort anwenden (verhindert Flackern)
  const sm = localStorage.getItem(SCHEME_KEY)||'light';
  if (sm === 'split') {
    root.dataset.scheme = 'split';
  } else {
    const dk = sm==='dark'||(sm==='system'&&window.matchMedia('(prefers-color-scheme: dark)').matches);
    if (dk) { const dv=DARK_VARS[dn]||DARK_VARS.standard; Object.entries(dv).forEach(([k,v])=>root.style.setProperty(k,v)); }
    root.dataset.scheme = dk ? 'dark' : 'light';
    if (sm==='system') { window.matchMedia('(prefers-color-scheme: dark)').addEventListener('change', _sysMQCb); }
  }
})();

