/* ── 5. App-Logo eingebettet ── */
const APP_LOGO_B64 = 'data:image/png;base64,';

function initAppLogo() {
  // Favicon setzen
  let favicon = document.querySelector('link[rel="icon"]');
  if (!favicon) { favicon = document.createElement('link'); favicon.rel = 'icon'; document.head.appendChild(favicon); }
  favicon.href = APP_LOGO_B64;
  // Sidebar-Logo setzen
  document.querySelectorAll('.brand-logo').forEach(img => { img.src = APP_LOGO_B64; });
}

/* ── 1. Avatar ── */
function initAvatar() {
  document.querySelectorAll('.av').forEach(el => {
    if (el.getAttribute('aria-hidden') === 'true') el.textContent = 'JS';
  });
}

/* ── 2. Auswertung-Link ── */
function initNavLinks() {
  document.querySelectorAll('a.nav-link').forEach(a => {
    if (!a.href && a.textContent.includes('Auswertung')) {
      a.href = 'auswertung.html';
    }
  });
}

/* ── 3. Pill dynamisch ── */
function updatePill() {
  try {
    const rechnungen = JSON.parse(localStorage.getItem(RECH_KEY)) || [];
    const offenCount = rechnungen.filter(r => r.status === 'offen').length;
    document.querySelectorAll('.pill').forEach(p => {
      if (p.closest('.nav-link') && p.closest('.nav-link').href &&
          p.closest('.nav-link').href.includes('rechnungen')) {
        p.textContent = offenCount;
        p.style.display = offenCount === 0 ? 'none' : '';
      }
    });
  } catch(e) {}
}

/* ── 4. Logo-Persistenz ── */
function saveLogo(dataURL) {
  try {
    localStorage.setItem(LOGO_KEY, dataURL);
    return true;
  } catch(e) {
    alert('Logo konnte nicht gespeichert werden – die Datei ist zu groß. Bitte ein kleineres Bild verwenden (max. ~1 MB).');
    return false;
  }
}
function loadLogo() {
  try { return localStorage.getItem(LOGO_KEY) || null; } catch(e) { return null; }
}
function clearLogo() {
  try { localStorage.removeItem(LOGO_KEY); } catch(e) {}
}

/* Komprimiert ein Bild-DataURL auf max. 400px Breite/Höhe, JPEG 80% */
function compressLogoDataURL(dataURL, callback) {
  const img = new Image();
  img.onload = function() {
    const MAX = 400;
    let w = img.width, h = img.height;
    if (w > MAX || h > MAX) {
      if (w > h) { h = Math.round(h * MAX / w); w = MAX; }
      else       { w = Math.round(w * MAX / h); h = MAX; }
    }
    const canvas = document.createElement('canvas');
    canvas.width = w; canvas.height = h;
    canvas.getContext('2d').drawImage(img, 0, 0, w, h);
    callback(canvas.toDataURL('image/jpeg', 0.80));
  };
  img.src = dataURL;
}

/* ── 6. Theme-System ── */
const THEME_KEY = 'max4work_theme';

const PRESET_THEMES = [
  { name: 'Weiß',   accent: '#ffffff', pale: '#f8f8f8', dark: '#1a1a1a' },
  { name: 'Lime',    accent: '#C8D93A', pale: '#F2F6D2', dark: '#2B3829' },
  { name: 'Blau',    accent: '#3B82F6', pale: '#EFF6FF', dark: '#1E3A5F' },
  { name: 'Lila',    accent: '#8B5CF6', pale: '#EDE9FE', dark: '#2E1065' },
  { name: 'Orange',  accent: '#F97316', pale: '#FFF7ED', dark: '#431407' },
  { name: 'Pink',    accent: '#EC4899', pale: '#FDF2F8', dark: '#500724' },
  { name: 'Teal',    accent: '#14B8A6', pale: '#F0FDFA', dark: '#134E4A' },
  { name: 'Rot',     accent: '#EF4444', pale: '#FEF2F2', dark: '#450A0A' },
  { name: 'Dunkel',  accent: '#6B7280', pale: '#F3F4F6', dark: '#111827' },
];

function _isLight(hex) {
  const r=parseInt(hex.slice(1,3),16), g=parseInt(hex.slice(3,5),16), b=parseInt(hex.slice(5,7),16);
  return (0.299*r + 0.587*g + 0.114*b) / 255 > 0.55;
}

function _hexToHsl(hex) {
  let r=parseInt(hex.slice(1,3),16)/255, g=parseInt(hex.slice(3,5),16)/255, b=parseInt(hex.slice(5,7),16)/255;
  const max=Math.max(r,g,b), min=Math.min(r,g,b); let h,s,l=(max+min)/2;
  if(max===min){h=s=0;}else{const d=max-min;s=l>0.5?d/(2-max-min):d/(max+min);switch(max){case r:h=(g-b)/d+(g<b?6:0);break;case g:h=(b-r)/d+2;break;case b:h=(r-g)/d+4;break;}h/=6;}
  return [Math.round(h*360),Math.round(s*100),Math.round(l*100)];
}
function _hslToHex(h,s,l) {
  s/=100;l/=100;const a=s*Math.min(l,1-l);
  const f=n=>{const k=(n+h/30)%12;const c=l-a*Math.max(-1,Math.min(k-3,9-k,1));return Math.round(255*c).toString(16).padStart(2,'0');};
  return `#${f(0)}${f(8)}${f(4)}`;
}
function _genPale(hex) { const [h,s]=_hexToHsl(hex); return _hslToHex(h,Math.min(s,50),94); }
function _genDark(hex) { const [h,s]=_hexToHsl(hex); return _hslToHex(h,Math.min(s+10,70),20); }

function applyTheme(theme) {
  if (!theme?.accent) return;
  const r = document.documentElement;
  const pale = theme.pale || _genPale(theme.accent);
  const dark = theme.dark || _genDark(theme.accent);
  const btnText = _isLight(theme.accent) ? '#1A1C18' : '#FFFFFF';
  r.style.setProperty('--accent', theme.accent);
  r.style.setProperty('--accent-pale', pale);
  r.style.setProperty('--dark', dark);
  let s = document.getElementById('max4work-theme-override');
  if (!s) { s = document.createElement('style'); s.id = 'max4work-theme-override'; document.head.appendChild(s); }
  const borderRule = _isLight(theme.accent) ? `.btn-blue,.btn-green,.btn-primary{border:1.5px solid rgba(0,0,0,0.18)!important;}` : `.btn-blue,.btn-green,.btn-primary{border:none!important;}`;
  s.textContent = `.btn-blue,.btn-green,.btn-primary{color:${btnText}!important;} .btn-blue:hover,.btn-green:hover{background:${theme.accent}cc!important;} ${borderRule}`;
}

function saveTheme(theme) {
  try { localStorage.setItem(THEME_KEY, JSON.stringify(theme)); } catch(e) {}
  applyTheme(theme);
}

function loadAndApplyTheme() {
  try { const t = JSON.parse(localStorage.getItem(THEME_KEY)); applyTheme(t || { accent: '#ffffff', pale: '#f8f8f8', dark: '#1a1a1a' }); } catch(e) {}
}

// Sofort anwenden (verhindert Farb-Flackern beim Laden)
loadAndApplyTheme();

/* ── Sidebar-Nutzerdaten dynamisch aus localStorage ── */
function updateSidebarUser() {
  try {
    const s = JSON.parse(localStorage.getItem('max4work_einstellungen') || '{}');
    const name  = s.sContact || '';
    const firma = s.sName    || '';
    const logo  = localStorage.getItem(LOGO_KEY);
    const wrap  = document.querySelector('.sidebar-user');
    const av    = document.querySelector('.av');
    const avName = document.querySelector('.av-name');
    const avSub  = document.querySelector('.av-sub');
    if (wrap) wrap.style.display = (name || firma) ? '' : 'none';
    if (avName) avName.textContent = name;
    if (avSub)  avSub.textContent  = firma;
    if (av) {
      if (logo) {
        av.classList.add('av--logo');
        av.innerHTML = `<img src="${logo}" alt="">`;
      } else {
        av.classList.remove('av--logo');
        av.textContent = name
          ? name.trim().split(/\s+/).map(w => w[0]).join('').substring(0, 2).toUpperCase()
          : '';
      }
    }
  } catch(e) {}
}
window.updateSidebarUser = updateSidebarUser;
document.addEventListener('DOMContentLoaded', updateSidebarUser);

