/* ── 7. Automatisches Backup-System ── */
const BACKUP_TS_KEY       = 'max4work_last_backup';
const BACKUP_DISMISS_KEY  = 'max4work_backup_dismissed';
const BACKUP_INTERVAL_KEY = 'max4work_backup_interval'; // Tage

function _backupDaysSince() {
  const ts = parseInt(localStorage.getItem(BACKUP_TS_KEY) || '0');
  if (!ts) return Infinity;
  return Math.floor((Date.now() - ts) / 86400000);
}

function _backupSize() {
  let bytes = 0;
  for (let k in localStorage) {
    if (k.startsWith('max4work_')) bytes += (localStorage[k]||'').length * 2;
  }
  return bytes > 1024*1024 ? (bytes/1024/1024).toFixed(1)+' MB' : Math.round(bytes/1024)+' KB';
}

function _backupJson() {
  const keys = [
    'max4work_kunden','max4work_rechnungen','max4work_rechnungen_history',
    'max4work_belege','max4work_termine','max4work_produkte','max4work_einstellungen',
    'max4work_zahlungen','max4work_theme','max4work_features',
    'max4work_fahrtenbuch','max4work_fahrzeuge',
    'max4work_rechnung_config','max4work_blattvorlagen',
    'max4work_mahn_config','max4work_wiederkehrend',
    'max4work_gobd_log','max4work_xrechnungen',
    'max4work_email_settings','max4work_email_signaturen',
    'max4work_portale','max4work_logo','max4work_ocr_key','max4work_ang_counter',
    'max4work_kassenbuch','max4work_kassenbuch_anfangsbestand',
    'max4work_rechnung_parken',
  ];
  const backup = { _version: '1.0', _app: 'max4work', _exportedAt: new Date().toISOString(), _size: _backupSize() };
  keys.forEach(k => { try { const v = localStorage.getItem(k); if (v) backup[k] = JSON.parse(v); } catch(e) {} });
  return JSON.stringify(backup, null, 2);
}

function _backupFilename() {
  return `max4work_backup_${new Date().toISOString().slice(0,16).replace('T','_').replace(':','-')}.json`;
}

function _openBackupDb() {
  return new Promise((resolve, reject) => {
    const req = indexedDB.open('max4work_fs', 1);
    req.onupgradeneeded = e => e.target.result.createObjectStore('handles');
    req.onsuccess = e => resolve(e.target.result);
    req.onerror = () => reject(req.error);
  });
}

async function _getBackupDirHandle() {
  try {
    const db = await _openBackupDb();
    return await new Promise(resolve => {
      const tx = db.transaction('handles', 'readonly');
      const req = tx.objectStore('handles').get('backupDir');
      req.onsuccess = () => resolve(req.result || null);
      req.onerror = () => resolve(null);
    });
  } catch(e) { return null; }
}

async function _saveBackupDirHandle(handle) {
  try {
    const db = await _openBackupDb();
    await new Promise((resolve, reject) => {
      const tx = db.transaction('handles', 'readwrite');
      tx.objectStore('handles').put(handle, 'backupDir');
      tx.oncomplete = resolve;
      tx.onerror = () => reject(tx.error);
    });
  } catch(e) {}
}

async function _resetBackupDir() {
  try {
    const db = await _openBackupDb();
    await new Promise(resolve => {
      const tx = db.transaction('handles', 'readwrite');
      tx.objectStore('handles').delete('backupDir');
      tx.oncomplete = resolve;
      tx.onerror = resolve;
    });
  } catch(e) {}
}

function _backupFallbackDownload(json, filename) {
  const blob = new Blob([json], { type: 'application/json' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url; a.download = filename; a.click();
  URL.revokeObjectURL(url);
}

function _backupFinish() {
  localStorage.setItem(BACKUP_TS_KEY, String(Date.now()));
  localStorage.removeItem(BACKUP_DISMISS_KEY);
  const banner = document.getElementById('_backupBanner');
  if (banner) { banner.style.animation = 'slideDown .3s ease reverse'; setTimeout(() => banner.remove(), 300); }
  _showBackupToast();
}

async function doQuickBackup() {
  const json = _backupJson();
  const filename = _backupFilename();

  if (window.showDirectoryPicker) {
    let dirHandle = await _getBackupDirHandle();

    // Prüfe gespeichertes Handle
    if (dirHandle) {
      try {
        const perm = await dirHandle.requestPermission({ mode: 'readwrite' });
        if (perm === 'granted') {
          const fh = await dirHandle.getFileHandle(filename, { create: true });
          const w = await fh.createWritable();
          await w.write(json); await w.close();
          _backupFinish(); return;
        }
      } catch(e) {
        // Handle ungültig → neu wählen
        await _resetBackupDir();
        dirHandle = null;
      }
    }

    // Erstmalig: Ordner auswählen
    try {
      dirHandle = await window.showDirectoryPicker({ mode: 'readwrite', startIn: 'desktop' });
      await _saveBackupDirHandle(dirHandle);
      const fh = await dirHandle.getFileHandle(filename, { create: true });
      const w = await fh.createWritable();
      await w.write(json); await w.close();
      _backupFinish(); return;
    } catch(e) {
      if (e.name === 'AbortError') return;
    }
  }

  // Fallback: normaler Download
  _backupFallbackDownload(json, filename);
  _backupFinish();
}

function _showBackupToast() {
  const t = document.createElement('div');
  t.style.cssText = 'position:fixed;bottom:24px;left:50%;transform:translateX(-50%);background:#2B3829;color:#fff;padding:10px 20px;border-radius:10px;font-size:13px;font-weight:500;z-index:9999;box-shadow:0 4px 16px rgba(0,0,0,.2);pointer-events:none;';
  t.textContent = '✓ Backup gespeichert';
  document.body.appendChild(t);
  setTimeout(() => t.remove(), 2500);
}

function _dismissBackup(days) {
  localStorage.setItem(BACKUP_DISMISS_KEY, String(Date.now() + days * 86400000));
  const banner = document.getElementById('_backupBanner');
  if (banner) { banner.style.animation = 'slideDown .25s ease reverse'; setTimeout(() => banner.remove(), 280); }
}

function _checkBackup() {
  const interval = parseInt(localStorage.getItem(BACKUP_INTERVAL_KEY) || '7');
  if (interval === 0) return; // deaktiviert
  const days = _backupDaysSince();
  if (days < interval) return;
  const dismissed = parseInt(localStorage.getItem(BACKUP_DISMISS_KEY) || '0');
  if (dismissed > Date.now()) return;

  const banner = document.createElement('div');
  banner.id = '_backupBanner';
  const label = days === Infinity ? 'Noch kein Backup erstellt' : `Letztes Backup vor ${days} Tag${days!==1?'en':''}`;
  banner.innerHTML = `
    <style>
      @keyframes slideUp { from { transform:translateY(100%); opacity:0; } to { transform:translateY(0); opacity:1; } }
      @keyframes slideDown { from { transform:translateY(0); opacity:1; } to { transform:translateY(100%); opacity:0; } }
      #_backupBanner { position:fixed;bottom:0;left:0;right:0;background:#1a1c18;color:#fff;padding:12px 20px;display:flex;align-items:center;gap:12px;z-index:9998;animation:slideUp .3s ease;font-family:'Outfit',sans-serif;font-size:13px; }
      #_backupBanner .bb-icon { font-size:16px;flex-shrink:0; }
      #_backupBanner .bb-text { flex:1; }
      #_backupBanner .bb-label { font-weight:600;margin-bottom:1px; }
      #_backupBanner .bb-sub { font-size:11.5px;opacity:.7; }
      #_backupBanner .bb-btn { background:#C8D93A;color:#1a1c18;border:none;border-radius:7px;padding:7px 16px;font-size:12.5px;font-weight:700;cursor:pointer;font-family:inherit;white-space:nowrap; }
      #_backupBanner .bb-btn:hover { background:#b8c930; }
      #_backupBanner .bb-skip { background:none;border:none;color:rgba(255,255,255,.5);font-size:12px;cursor:pointer;font-family:inherit;padding:4px 8px;white-space:nowrap; }
      #_backupBanner .bb-skip:hover { color:rgba(255,255,255,.8); }
    </style>
    <div class="bb-icon">
      <svg width="18" height="18" fill="none" stroke="currentColor" stroke-width="1.8" viewBox="0 0 24 24"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="17 8 12 3 7 8"/><line x1="12" y1="3" x2="12" y2="15"/></svg>
    </div>
    <div class="bb-text">
      <div class="bb-label">${label}</div>
      <div class="bb-sub">Datengröße: ${_backupSize()} · Alle Rechnungen, Kunden, Belege & Termine</div>
    </div>
    <button class="bb-btn" onclick="doQuickBackup()">Jetzt sichern</button>
    <button class="bb-skip" onclick="_dismissBackup(1)">Morgen</button>
    <button class="bb-skip" onclick="_dismissBackup(3)">3 Tage</button>
    <button class="bb-skip" style="font-size:16px;padding:4px 10px;" onclick="_dismissBackup(30)">×</button>`;
  document.body.appendChild(banner);
}

