/* ── Enter → nächstes Eingabefeld ── */
function _getFocusables() {
  return [...document.querySelectorAll(
    'input:not([type="hidden"]):not([type="submit"]):not([type="button"]):not([type="reset"]):not([type="checkbox"]):not([type="radio"]):not([type="file"]):not([disabled]):not([readonly]), select:not([disabled]), textarea:not([disabled])'
  )].filter(el => {
    const s = window.getComputedStyle(el);
    return s.display !== 'none' && s.visibility !== 'hidden';
  });
}

document.addEventListener('keydown', e => {
  if (e.key !== 'Enter') return;
  const el = e.target;
  if (!['INPUT', 'SELECT'].includes(el.tagName)) return;
  if (el.tagName === 'INPUT' && ['submit','button','reset','checkbox','radio','file'].includes(el.type)) return;
  e.preventDefault();
  const all = _getFocusables();
  const idx = all.indexOf(el);
  if (idx >= 0 && idx < all.length - 1) all[idx + 1].focus();
});

